using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string ModelId = "gpt-4o-mini-2024-07-18";

// --- DI container ------------------------------------------------------------

var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(b => b
    .UseOpenAIChatClient(ModelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();

// --- Tools -------------------------------------------------------------------

var tools = new ResearchTools();

var aiTools = new AIFunction[]
{
    AIFunctionFactory.Create(tools.SearchWeb),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

// --- Agent setup -------------------------------------------------------------

var chatClient = sp.GetRequiredService<IChatClient>();

var agent = new ChatClientAgent(chatClient, aiTools)
{
    Name = "ResearchAgent",
    Instructions = """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using the SearchWeb tool (make multiple searches with different queries to get broad coverage).
        2. Save important findings as notes using the SaveNote tool.
        3. After gathering enough information, use GetNotes to review all your notes.
        4. Provide a well-structured summary with key findings, organized by theme.
        Be thorough but concise. Cite the sources from your search results.
        """,
};

// --- Run the agent -----------------------------------------------------------

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n✅ Research complete.");

