using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string ModelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var researchTools = new ResearchTools();

var aiTools = new List<AITool>
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.SaveNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// --- Agent setup -------------------------------------------------------------

var chatClient = new OpenAIClient(apiKey)
    .GetChatClient(ModelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using the SearchWeb tool
           (make multiple searches with different queries to get broad coverage).
        2. Save important findings as notes using the SaveNote tool.
        3. After gathering enough information, use GetNotes to review all your notes.
        4. Provide a well-structured summary with key findings, organized by theme.
        Be thorough but concise. Cite the sources from your search results.
        """,
    name: "ResearchAgent",
    tools: aiTools);

// --- Run the agent -----------------------------------------------------------

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a summary: {topic}",
    session,
    runOptions))
{
    if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine("\n\n✅ Research complete.");

