76. // --- Helpers -----------------------------------------------------------------
77. 
78. static string PromptForTopic()
79. {
80.     Console.Write("Enter a research topic: ");
81.     var input = Console.ReadLine()?.Trim();
82.     return string.IsNullOrEmpty(input)
83.         ? throw new InvalidOperationException("A research topic is required.")
84.         : input;
85. }
86. 
87. // =============================================================================
88. // Tools
89. // =============================================================================
90. 
91. sealed class ResearchTools
92. {
93.     private readonly List<string> _notes = [];
94.     private static readonly HttpClient Http = new()
95.     {
96.         DefaultRequestHeaders =
97.         {
98.             { "User-Agent", "ResearchAgent/1.0" },
99.         },
100.     };
101. 
102.     [Description("Search the web for information on a query. Returns a list of result snippets with titles and URLs.")]
103.     public async Task<string> SearchWeb(
104.         [Description("The search query string")] string query)
105.     {
106.         Console.WriteLine($"  🌐 Searching: \"{query}\"");
107. 
108.         try
109.         {
110.             var encoded = WebUtility.UrlEncode(query);
111.             var url = $"https://html.duckduckgo.com/html/?q={encoded}";
112. 
113.             var request = new HttpRequestMessage(HttpMethod.Get, url);
114.             request.Headers.Add("Accept", "text/html");
115. 
116.             var response = await Http.SendAsync(request);
117.             var html = await response.Content.ReadAsStringAsync();
118. 
119.             var results = ParseSearchResults(html);
120. 
121.             if (results.Count == 0)
122.             {
123.                 return JsonSerializer.Serialize(new { query, message = "No results found.", results = Array.Empty<object>() });
124.             }
125. 
126.             return JsonSerializer.Serialize(new { query, resultCount = results.Count, results });
127.         }
128.         catch (Exception ex)
129.         {
130.             return JsonSerializer.Serialize(new { query, error = ex.Message });
131.         }
132.     }
133. 
134.     [Description("Save an important finding as a note for later summarization.")]
135.     public string SaveNote(
136.         [Description("A concise note capturing a key finding")] string note,
137.         [Description("The source URL or reference for this finding")] string source)
138.     {
139.         _notes.Add($"[{_notes.Count + 1}] {note} (Source: {source})");
140.         Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
141.         return $"Note saved. You now have {_notes.Count} note(s).";
142.     }
143. 
144.     [Description("Retrieve all saved notes to review before writing the final summary.")]
145.     public string GetNotes()
146.     {
147.         if (_notes.Count == 0)
148.         {
149.             return "No notes saved yet.";
150.         }
151. 
152.         Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
153.         return string.Join("\n", _notes);
154.     }
155. 
156.     private static List<object> ParseSearchResults(string html)
157.     {
158.         var results = new List<object>();
159.         var snippetTag = "class=\"result__snippet\"";
160.         var titleTag = "class=\"result__a\"";
161.         var idx = 0;
162. 
163.         while (results.Count < 5)
164.         {
165.             var titleStart = html.IndexOf(titleTag, idx, StringComparison.Ordinal);
166.             if (titleStart < 0) break;
167. 
168.             var href = ExtractAttribute(html, titleStart, "href");
