 using System.ComponentModel;
 using System.Net;
 using System.Text.Json;
 using Microsoft.Agents.AI;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Configuration -----------------------------------------------------------

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 const string ModelId = "gpt-4o-mini-2024-07-18";

 // --- Tools -------------------------------------------------------------------

 var researchTools = new ResearchTools();

 var aiTools = new List<AITool>
 {
     AIFunctionFactory.Create(researchTools.SearchWeb),
     AIFunctionFactory.Create(researchTools.SaveNote),
     AIFunctionFactory.Create(researchTools.GetNotes),
 };

 // --- Agent setup -------------------------------------------------------------

 var chatClient = new OpenAIClient(apiKey)
     .GetChatClient(ModelId)
     .AsIChatClient();

 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research assistant. When given a topic:
         1. Search the web for relevant information using the SearchWeb tool
            (make multiple searches with different queries to get broad coverage).
         2. Save important findings as notes using the SaveNote tool.
         3. After gathering enough information, use GetNotes to review all your notes.
         4. Provide a well-structured summary with key findings, organized by theme.
         Be thorough but concise. Cite the sources from your search results.
         """,
     name: "ResearchAgent",
     tools: aiTools);

 // --- Run the agent -----------------------------------------------------------

 var topic = args.Length > 0
     ? string.Join(' ', args)
     : PromptForTopic();

 Console.WriteLine($"\n🔍 Researching: {topic}\n");

 var session = await agent.CreateSessionAsync();

 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 4096,
 });

 await foreach (var update in agent.RunStreamingAsync(
     $"Research the following topic and provide a summary: {topic}",
     session,
     runOptions))
 {
     if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
     {
         Console.Write(update.Text);
     }
 }

 Console.WriteLine("\n\n✅ Research complete.");

 // --- Helpers -----------------------------------------------------------------

 static string PromptForTopic()
 {
     Console.Write("Enter a research topic: ");
     var input = Console.ReadLine()?.Trim();
     return string.IsNullOrEmpty(input)
         ? throw new InvalidOperationException("A research topic is required.")
         : input;
 }

 // =============================================================================
 // Tools
 // =============================================================================

 sealed class ResearchTools
 {
     private readonly List<string> _notes = [];
     private static readonly HttpClient Http = new()
     {
         DefaultRequestHeaders =
         {
             { "User-Agent", "ResearchAgent/1.0" },
         },
     };

     [Description("Search the web for information on a query. Returns a list of result snippets with titles and URLs.")]
     public async Task<string> SearchWeb(
         [Description("The search query string")] string query)
     {
         Console.WriteLine($"  🌐 Searching: \"{query}\"");

         try
         {
             var encoded = WebUtility.UrlEncode(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";

             var request = new HttpRequestMessage(HttpMethod.Get, url);
             request.Headers.Add("Accept", "text/html");

             var response = await Http.SendAsync(request);
             var html = await response.Content.ReadAsStringAsync();

             var results = ParseSearchResults(html);

             if (results.Count == 0)
             {
                 return JsonSerializer.Serialize(new { query, message = "No results found.", results = Array.Empty<object>() });
             }

             return JsonSerializer.Serialize(new { query, resultCount = results.Count, results });
         }
         catch (Exception ex)
         {
             return JsonSerializer.Serialize(new { query, error = ex.Message });
         }
     }

     [Description("Save an important finding as a note for later summarization.")]
     public string SaveNote(
         [Description("A concise note capturing a key finding")] string note,
         [Description("The source URL or reference for this finding")] string source)
     {
         _notes.Add($"[{_notes.Count + 1}] {note} (Source: {source})");
         Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
         return $"Note saved. You now have {_notes.Count} note(s).";
     }

     [Description("Retrieve all saved notes to review before writing the final summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes saved yet.";
         }

         Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
         return string.Join("\n", _notes);
     }

     private static List<object> ParseSearchResults(string html)
     {
         var results = new List<object>();
         var snippetTag = "class=\"result__snippet\"";
         var titleTag = "class=\"result__a\"";
         var idx = 0;

         while (results.Count < 5)
         {
             var titleStart = html.IndexOf(titleTag, idx, StringComparison.Ordinal);
             if (titleStart < 0) break;

             var href = ExtractAttribute(html, titleStart, "href");
             var titleText = ExtractTagContent(html, titleStart);

             var snippetStart = html.IndexOf(snippetTag, titleStart, StringComparison.Ordinal);
             var snippetText = snippetStart >= 0 ? ExtractTagContent(html, snippetStart) : "";

             if (!string.IsNullOrWhiteSpace(titleText))
             {
                 results.Add(new { title = CleanHtml(titleText), url = href ?? "", snippet = CleanHtml(snippetText) });
             }

             idx = snippetStart >= 0 ? snippetStart + 1 : titleStart + 1;
         }

         return results;
     }

     private static string? ExtractAttribute(string html, int startIdx, string attr)
     {
         var searchBack = Math.Max(0, startIdx - 500);
         var region = html[searchBack..startIdx];
         var attrPattern = $"{attr}=\"";
         var attrIdx = region.LastIndexOf(attrPattern, StringComparison.Ordinal);
         if (attrIdx < 0) return null;
         var valStart = attrIdx + attrPattern.Length;
         var valEnd = region.IndexOf('"', valStart);
         return valEnd > valStart ? region[valStart..valEnd] : null;
     }

     private static string ExtractTagContent(string html, int attrIdx)
     {
         var closeTag = html.IndexOf('>', attrIdx);
         if (closeTag < 0) return "";
         var endTag = html.IndexOf('<', closeTag + 1);
         return endTag > closeTag ? html[(closeTag + 1)..endTag] : "";
     }

     private static string CleanHtml(string text) =>
         WebUtility.HtmlDecode(text).Trim();
 }

